const body = $json.body || $json;
if (!body.action) throw new Error('action zorunlu');

const action = body.action.trim().toLowerCase();
const payload = body.payload || {};
const session_key = body.session_key || '';

// Oturum gerektiren action'lar
const SESSION_REQUIRED = ['check_quota', 'upload_receipt', 'get_reports'];
if (SESSION_REQUIRED.includes(action) && !session_key) {
  throw new Error('Bu islem icin session_key zorunlu');
}

return [{ json: { action, payload, session_key, _step: 1 } }];

// ================================================================
//  DYNAMIC SQL ENGINE - (TÜM MODÜLLER DAHİL - TAM SÜRÜM)
// ================================================================
const { action, payload, session_key, _step, _prev } = $json;

const ACTIONS = {
  // --- 1. GİRİŞ VE OTURUM (AUTH) ---
  login: {
    1: {
      validate: () => { if (!payload.email || !payload.password) throw new Error('E-posta ve şifre zorunlu'); },
      sql: `SELECT u.id, u.company_id, u.role, u.is_super_admin FROM users u 
            WHERE lower(u.email) = lower($1) AND u.password_hash = crypt($2, u.password_hash) AND u.status = 'true' LIMIT 1`,
      params: () => [payload.email, payload.password]
    },
    2: {
      sql: `INSERT INTO user_sessions (user_id, session_key, expires_at, user_agent) 
            VALUES ($1, encode(gen_random_bytes(32), 'hex'), now() + interval '15 days', $2) 
            RETURNING session_key`,
      params: () => [_prev.id, payload.user_agent || 'web']
    }
  },

  // --- 2. KAYIT VE KOTA (SİSTEM) ---
  register: {
    1: {
      validate: () => { if (!payload.company_name || !payload.email || !payload.password) throw new Error('Eksik kayıt bilgileri'); },
      sql: `SELECT create_trial_company_and_admin($1, $2, crypt($3, gen_salt('bf')), $4) AS user_id`,
      params: () => [payload.company_name, payload.email, payload.password, payload.telegram_id || null]
    }
  },

  check_quota: {
    1: {
      sql: `SELECT c.id AS company_id, check_company_quota(c.id) AS allow
            FROM user_sessions s JOIN users u ON u.id = s.user_id JOIN companies c ON c.id = u.company_id
            WHERE s.session_key = $1 AND s.revoked_at IS NULL LIMIT 1`,
      params: () => [session_key]
    }
  },

  // --- 3. RAPOR VE LİSTELEME (VERİ) ---
  get_reports: {
    1: {
      sql: `SELECT u.id AS user_id, u.role, u.is_super_admin, u.company_id, c.company_name, c.used_this_month, c.monthly_limit, c.plan_type
            FROM user_sessions s JOIN users u ON u.id = s.user_id LEFT JOIN companies c ON c.id = u.company_id
            WHERE s.session_key = $1 AND s.revoked_at IS NULL LIMIT 1`,
      params: () => [session_key]
    }
  },

  get_receipts: {
    1: {
      sql: `SELECT f.* FROM fisler f 
            JOIN users u ON u.company_id = f.company_id 
            JOIN user_sessions s ON s.user_id = u.id
            WHERE s.session_key = $1 AND s.revoked_at IS NULL 
            ORDER BY f.tarih DESC, f.saat DESC LIMIT 100`,
      params: () => [session_key]
    }
  },

  // --- 4. FİŞ YÖNETİMİ (İŞLEM) ---
  update_receipt: {
    1: {
      validate: () => { if (!payload.receipt_id || !payload.data) throw new Error('ID veya veri eksik'); },
      sql: `UPDATE fisler SET 
              isletme_adi = $1, toplam_tutar = $2, tarih = $3, saat = $4, durum = $5, 
              kategori = $6, proje = $7, fis_no = $8, kart_son_4 = $9, ocr_detaylari = $10::jsonb
            WHERE id = $11 AND company_id = (SELECT company_id FROM users u JOIN user_sessions s ON u.id = s.user_id WHERE s.session_key = $12)
            RETURNING id`,
      params: () => [
        payload.data.isletme_adi, payload.data.toplam_tutar, payload.data.tarih, payload.data.saat, payload.data.durum,
        payload.data.kategori, payload.data.proje, payload.data.fis_no, payload.data.kart_son_4,
        JSON.stringify(payload.data.ocr_detaylari || []), payload.receipt_id, session_key
      ]
    }
  },

  delete_receipt: {
    1: {
      sql: `DELETE FROM fisler WHERE id = $1 AND company_id = (SELECT company_id FROM users u JOIN user_sessions s ON u.id = s.user_id WHERE s.session_key = $2) RETURNING id`,
      params: () => [payload.receipt_id, session_key]
    }
  },

  // --- 5. EKİP VE METADATA (YÖNETİM) ---
  manage_metadata: {
    1: {
      sql: `SELECT * FROM ${payload.table === 'projects' ? 'projects' : 'categories'} 
            WHERE company_id = (SELECT company_id FROM users u JOIN user_sessions s ON u.id = s.user_id WHERE s.session_key = $1)
            ORDER BY name ASC`,
      params: () => [session_key]
    }
  },

  get_team: {
    1: {
      sql: `SELECT id, email, full_name, role, status, phone_number FROM users 
            WHERE company_id = (SELECT company_id FROM users u JOIN user_sessions s ON u.id = s.user_id WHERE s.session_key = $1)`,
      params: () => [session_key]
    }
  },

  forgot_password: {
    1: {
      validate: () => { if (!payload.email) throw new Error('E-posta zorunlu'); },
      sql: `SELECT id, email, coalesce(full_name, split_part(email, '@', 1)) AS full_name FROM users WHERE lower(email) = lower($1) AND status = 'true' LIMIT 1`,
      params: () => [payload.email]
    },
    2: {
      sql: `UPDATE users SET password_hash = crypt($1, gen_salt('bf')), updated_at = now() WHERE id = $2 RETURNING id`,
      params: () => [_prev.temp_password, _prev.user_id]
    }
  }
};

// --- ROUTER MANTIĞI ---
const actionDef = ACTIONS[action];
if (!actionDef) return [{ json: { _done: true, _response: { ok: false, message: 'Bilinmeyen işlem: ' + action } } }];

const stepDef = actionDef[_step];
if (!stepDef) return [{ json: { _done: true, _response: { ok: false, message: 'Geçersiz adım' } } }];

if (stepDef.validate) stepDef.validate();

return [{ json: { 
  action, payload, session_key, _step, 
  _sql: stepDef.sql, 
  _params: stepDef.params(), 
  _prev: _prev || null 
}}];

const input = $('SQL Engine').first().json;
const { action, payload, session_key, _step } = input;
const rows = $input.all().map(i => i.json);
const row = rows[0] || {};

if (action === 'login' && _step === 1) {
  if (!row.id) throw new Error('Hatalı giris');
  return [{ json: { action, payload, session_key, _step: 2, _prev: row, _done: false }}];
}
if (action === 'login' && _step === 2) {
  return [{ json: { _done: true, _response: { ok: true, session_key: row.session_key } } }];
}

if (action === 'check_quota') {
  return [{ json: { _done: true, _response: { ok: true, allow: row.allow || false } } }];
}

if (action === 'get_reports') {
  return [{ json: { _done: true, _response: { 
    ok: true, 
    profile: { user_id: row.user_id, role: row.role, is_super_admin: row.is_super_admin },
    company: { name: row.company_name, used: row.used_this_month, limit: row.monthly_limit }
  } } }];
}

if (action === 'get_receipts') {
  const normalized = rows.map(r => ({ ...r, ocr_detaylari: r.ocr_detaylari?.urunler || r.ocr_detaylari || [] }));
  return [{ json: { _done: true, _response: { ok: true, receipts: normalized } } }];
}

if (action === 'manage_metadata') {
  return [{ json: { _done: true, _response: { ok: true, [payload.table]: rows } } }];
}

return [{ json: { _done: true, _response: { ok: true, message: 'Islem tamamlandi' } } }];
